const p=[1,1,1.5,1.5,2,2,3];function d(t){const{basePrice:e,stepPercent:o,baseShares:c,maxLevels:i=7}=t,n=p.slice(0,i),r=[];let a=0,u=0;for(let s=0;s<n.length;s++){const h=n[s],m=e*Math.pow(1-o/100,s),l=Math.round(c*h),v=l*m;a+=l,u+=v,r.push({level:s+1,ratio:h,price:Math.round(m*100)/100,shares:l,investment:Math.round(v*100)/100,cumulativeShares:a,cumulativeInvestment:Math.round(u*100)/100,averageCost:Math.round(u/a*100)/100})}return r}function g(t){if(t.length===0)return null;const e=t[t.length-1],o=e.cumulativeInvestment,c=e.cumulativeShares,i=e.averageCost,n=t[0].price,r=e.price,a=(n-r)/n*100;return{totalInvestment:Math.round(o*100)/100,totalShares:c,averageCost:i,firstPrice:n,lastPrice:r,totalLevels:t.length,priceDropPercent:Math.round(a*100)/100,maxDrawdown:Math.round(a*100)/100}}export{g as a,d as g};
